public class TestRunner {
    static int passed = 0;
    static int failed = 0;

    public static void main(String[] args) {
        LoanApprovalSystem sys = new LoanApprovalSystem(10_000_000.0);

        // ── Approved: valid application ──
        check("Gru approved",
              "Approved: Gru (processed)",
              sys.processApplication("Gru", "2000000", "9"));

        // ── Approved: second valid ──
        check("Vector approved",
              "Approved: Vector (processed)",
              sys.processApplication("Vector", "1500000", "8"));

        // ── Denied: low evilness ──
        check("low evilness denied",
              "Denied: Insufficient evilness (processed)",
              sys.processApplication("Random Guy", "500000", "3"));

        // ── Denied: invalid amount string ──
        check("bad amount string",
              "Denied: Invalid amount: not-a-number (processed)",
              sys.processApplication("El Macho", "not-a-number", "9"));

        // ── Denied: invalid score string ──
        check("bad score string",
              "Denied: Invalid score: evil (processed)",
              sys.processApplication("Dr. Bad", "1000000", "evil"));

        // ── Denied: amount too low ──
        check("amount too low",
              "Denied: Amount out of range (processed)",
              sys.processApplication("Tiny Tim", "5", "9"));

        // ── Denied: amount too high ──
        check("amount too high",
              "Denied: Amount out of range (processed)",
              sys.processApplication("Megalomaniac", "9999999", "10"));

        // ── Denied: score out of range ──
        check("score out of range",
              "Denied: Score must be 1-10 (processed)",
              sys.processApplication("Overachiever", "100000", "11"));

        // ── Denied: blank villain name ──
        check("blank name denied",
              "Denied: Villain name required (processed)",
              sys.processApplication("", "100000", "9"));

        // ── Denied: insufficient funds (after Gru + Vector used 3.5M of 10M) ──
        // Approve 4 more to drain funds to < 1M, then try another
        sys.processApplication("Scarlet", "2000000", "10");  // running total: 5.5M used
        sys.processApplication("Balthazar", "2000000", "9"); // 7.5M used
        sys.processApplication("Nefario",   "2000000", "8"); // 9.5M used
        check("insufficient funds",
              "Denied: Insufficient funds (processed)",
              sys.processApplication("Villain X", "1000000", "9"));

        // ── finally always appends (processed) ──
        String r = sys.processApplication("Ghost", "bad", "9");
        checkBool("finally always appends (processed)",
                  true, r != null && r.endsWith("(processed)"));

        // ── summary ──
        System.out.println();
        int total = passed + failed;
        System.out.println((passed == total ? "PASS" : "FAIL")
            + ": " + passed + "/" + total + " tests passed");
    }

    static void check(String label, String expected, String actual) {
        if (expected.equals(actual)) {
            System.out.println("PASS: " + label); passed++;
        } else {
            System.out.println("FAIL: " + label
                + " \u2014 expected \"" + expected
                + "\" but got \"" + actual + "\""); failed++;
        }
    }
    static void checkBool(String label, boolean expected, boolean actual) {
        if (expected == actual) {
            System.out.println("PASS: " + label); passed++;
        } else {
            System.out.println("FAIL: " + label
                + " \u2014 expected " + expected + " but got " + actual); failed++;
        }
    }
    static void fail(String label, Exception e) {
        System.out.println("FAIL: " + label + " \u2014 " + e); failed++;
    }
}
